try {
  // Lấy dữ liệu từ OCR
  const parsedResults = $json.ParsedResults;
  if (!parsedResults || parsedResults.length === 0) throw new Error("OCR không đọc được chữ nào từ ảnh!");

  const ocrText = parsedResults[0].ParsedText;

  // Lấy Caption từ tin nhắn Telegram
  const caption = $('gửi ảnh Telegram').item.json.message.caption || '';

  // Regex mới: Chấp nhận cả "P101", "Phòng 101" hoặc chỉ nhắn mỗi "101"
  const matchPhong = caption.match(/(?:P|#|Phòng\s*)?(\d{3,4})/i);
  const phong = matchPhong ? matchPhong[1] : '???';

  if (phong === '???') throw new Error("Lỗi: Bạn chưa ghi mã phòng ở phần Caption (ví dụ: P101)");

  // Tìm số lớn nhất trong ảnh (thường là chỉ số điện mới)
  const numbers = ocrText.match(/\d+/g);
  let chiSoMoi = 0;
  if (numbers && numbers.length > 0) {
    chiSoMoi = Math.max(...numbers.map(Number)); 
  }

  return {
    json: {
      phong: phong,
      chiSoDienMoi: chiSoMoi,
      nguon: "AI_OCR_ADMIN"
    }
  };
} catch (error) {
  throw new Error(error.message);
}

