const input = $input.item.json;
const isAI = input.nguon === "AI_OCR_ADMIN";

function getV(key) {
    if (input[key] !== undefined && input[key] !== null) return input[key];
    if (input.body && input.body[key] !== undefined) return input.body[key];
    return 0; 
}

const phong = getV('phong') || getV('ma_phong') || "?";
const hoTen = getV('hoTen') || getV('ho_ten') || "Khách hàng";
const email = getV('email') || "clm@example.com";

const today = new Date();
const thangNam = getV('thangNam') || getV('thang_nam') || `${today.getMonth() + 1}/${today.getFullYear()}`;

let baseRent = Number(getV('tienPhong') || getV('tien_phong') || 0);
let tongTuReact = Number(getV('tongTien') || getV('tong_tien') || 0);

let val_dien = 0;
let val_nuoc = 0;
let finalTotal = 0;

if (tongTuReact > 0 && !isAI) {
    baseRent = tongTuReact;
    finalTotal = tongTuReact;
} else {
    const sd = Number(getV('chiSoDienMoi')) - Number(getV('chiSoDienCu'));
    const sn = Number(getV('chiSoNuocMoi')) - Number(getV('chiSoNuocCu'));

    val_dien = Math.max(0, sd * 3500); 
    val_nuoc = Math.max(0, sn * 100000); 

    finalTotal = baseRent + val_dien + val_nuoc;
}

const fmt = (v) => new Intl.NumberFormat('vi-VN').format(v) + ' đ';

return {
    json: {
        ...input, 
        phong, hoTen, email,
        is_auto: false,
        val_phong: baseRent,
        val_tong: finalTotal,
        txt_phong: fmt(baseRent),
        txt_tong: fmt(finalTotal),
        thangDisplay: thangNam,
        qrUrl: `https://img.vietqr.io/image/MB-0905881525-compact2.png?amount=${finalTotal}&addInfo=ThanhToan_P${phong}&accountName=HUYNH%20NGOC%20HUY`,
        chi_so_dien_cu: Number(getV('chiSoDienCu')),
        chi_so_dien_moi: Number(getV('chiSoDienMoi')),
        chi_so_nuoc_cu: Number(getV('chiSoNuocCu')),
        chi_so_nuoc_moi: Number(getV('chiSoNuocMoi'))
    }
};

const payloadData = $input.item.json.body.data;
const signature = $input.item.json.body.signature;

if (!payloadData || !signature) return { valid: false, signData: "", originalSignature: "" };

const sortedKeys = Object.keys(payloadData).sort();
const signDataArr = [];
for(const k of sortedKeys) {
    if(payloadData[k] !== undefined && payloadData[k] !== null && typeof payloadData[k] !== 'object' && typeof payloadData[k] !== 'array') {
        signDataArr.push(`${k}=${payloadData[k]}`);
    }
}
const signData = signDataArr.join('&');

return {
  signData: signData,
  originalSignature: signature,
  bodyData: payloadData
};

